import os
import boto3
from botocore.exceptions import NoCredentialsError, PartialCredentialsError
import pickle

def load_latest_model_from_s3(bucket_name, model_path):
    s3 = boto3.client('s3')
    try:
        response = s3.list_objects_v2(Bucket=bucket_name, Prefix=model_path)
        if 'Contents' not in response:
            raise Exception("No models found in the specified path.")
        
        models = response['Contents']
        latest_model = max(models, key=lambda x: x['LastModified'])
        model_key = latest_model['Key']
        
        model_obj = s3.get_object(Bucket=bucket_name, Key=model_key)
        model_data = model_obj['Body'].read()
        model = pickle.loads(model_data)
        return model
    except (NoCredentialsError, PartialCredentialsError):
        raise Exception("AWS credentials not found or incomplete.")
    except Exception as e:
        raise Exception(f"Error loading model: {str(e)}")

